function App() {
  const [user, setUser] = useState(null);
  const [authReady, setAuthReady] = useState(false);
  const [isDark, setIsDark] = useState(false);
  const [tab, setTab] = useState("dashboard");
  const [units, setUnits] = useState("metric");
  const [parish, setParish] = useState(null);
  const [dropOpen, setDropOpen] = useState(false);
  const [weather, setWeather] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [mapLayer, setMapLayer] = useState("temp");

  // Auth form states
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [formError, setFormError] = useState('');
  const [formLoading, setFormLoading] = useState(false);
  const [page, setPage] = useState('login');

  // Admin states
  const [alertMessage, setAlertMessage] = useState('');
  const [sending, setSending] = useState(false);
  const [sendStatus, setSendStatus] = useState('');
  const [users, setUsers] = useState([]);

  const dropRef = useRef(null);
  const T = getTheme(isDark);
  const current = weather?.current;
  const tUnit = units==="metric"?"°C":"°F";

  // Restore session
  useEffect(() => {
    const token = localStorage.getItem('auth_token');
    const storedUser = localStorage.getItem('user');
    if (token && storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setAuthReady(true);
  }, []);

  // Load parish from user
  useEffect(() => {
    if (!user) return;
    const p = PARISHES.find(x=>x.id===user.parish)||PARISHES[0];
    setParish(p);
    fetchWeather(p.lat, p.lon, units);
  }, [user]);

  // Close dropdown on outside click
  useEffect(() => {
    const h = e => { if(dropRef.current && !dropRef.current.contains(e.target)) setDropOpen(false); };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);

  // Fetch users for admin
  useEffect(() => {
    if (user && user.role === 'admin' && tab === 'admin') {
      fetchUsers();
    }
  }, [user, tab]);

  const fetchUsers = async () => {
    try {
      const response = await fetch(`${API_BASE}/get_users.php`);
      const data = await response.json();
      if (data.success) {
        setUsers(data.users);
      }
    } catch (error) {
      console.error('Failed to fetch users:', error);
    }
  };

  const fetchWeather = useCallback(async (lat, lon, u=units) => {
    setLoading(true); setError(null);
    try {
      const params = new URLSearchParams({
        latitude: lat.toString(),
        longitude: lon.toString(),
        current: "temperature_2m,relative_humidity_2m,is_day,precipitation,rain,showers,cloud_cover,wind_speed_10m,wind_direction_10m",
        hourly: "temperature_2m,relative_humidity_2m,precipitation_probability,precipitation,rain,showers,cloud_cover,wind_speed_10m",
        daily: "temperature_2m_max,temperature_2m_min,sunrise,sunset,precipitation_sum,precipitation_probability_max",
        temperature_unit: u === "metric" ? "celsius" : "fahrenheit",
        wind_speed_unit: u === "metric" ? "kmh" : "mph",
        precipitation_unit: "mm",
        timezone: "auto",
        forecast_days: 14
      });

      const response = await fetch(`${OPENMETEO_BASE}?${params}`);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();

      if (!data || !data.current) {
        throw new Error("No weather data available");
      }

      const getWeatherDescription = (cloudCover, precip, rain, showers) => {
        if (rain > 0 || showers > 0) return precip > 5 ? "Heavy Rain" : "Light Rain";
        if (cloudCover > 75) return "Cloudy";
        if (cloudCover > 40) return "Partly Cloudy";
        return "Clear";
      };

      const currentData = data.current;
      const hourly = data.hourly;
      const daily = data.daily;

      const transformed = {
        current: {
          temperature: Math.round(currentData.temperature_2m),
          feels_like: Math.round(currentData.temperature_2m),
          summary: getWeatherDescription(currentData.cloud_cover, currentData.precipitation, currentData.rain, currentData.showers),
          weather: currentData.is_day ? "day" : "night",
          wind: {
            speed: Math.round(currentData.wind_speed_10m),
            direction: currentData.wind_direction_10m || 0
          },
          cloud_cover: Math.round(currentData.cloud_cover || 0),
          precipitation: {
            total: currentData.precipitation || 0
          },
          rain: currentData.rain || 0,
          showers: currentData.showers || 0,
          humidity: Math.round(currentData.relative_humidity_2m || 0),
          pressure: 1013,
        },
        hourly: {
          data: hourly.time.slice(0, 24).map((time, i) => ({
            date: time,
            temperature: Math.round(hourly.temperature_2m[i]),
            summary: getWeatherDescription(
              hourly.cloud_cover[i], 
              hourly.precipitation[i], 
              hourly.rain[i], 
              hourly.showers[i]
            ),
            weather: "auto",
            precipitation: {
              total: hourly.precipitation[i] || 0,
              probability: hourly.precipitation_probability[i] || 0
            },
            wind: {
              speed: Math.round(hourly.wind_speed_10m[i] || 0)
            },
            cloud_cover: Math.round(hourly.cloud_cover[i] || 0),
            rain: hourly.rain[i] || 0,
            showers: hourly.showers[i] || 0
          }))
        },
        daily: {
          data: daily.time.slice(0, 7).map((time, i) => ({
            day: time,
            all_day: {
              temperature_max: Math.round(daily.temperature_2m_max[i]),
              temperature_min: Math.round(daily.temperature_2m_min[i]),
              weather: "auto",
              summary: daily.precipitation_sum[i] > 5 ? "Rain" : "Partly Cloudy",
              precipitation_sum: daily.precipitation_sum[i] || 0,
              precipitation_probability: daily.precipitation_probability_max[i] || 0
            },
            summary: daily.precipitation_sum[i] > 5 ? "Rain" : "Partly Cloudy",
            sunrise: daily.sunrise[i],
            sunset: daily.sunset[i]
          }))
        }
      };

      setWeather(transformed);

      // Auto-detect alerts for admin
      if (user && user.role === 'admin') {
        detectAndStoreAlerts(transformed, parish);
      }
    } catch(e) { 
      console.error("Weather fetch error:", e);
      setError(`Weather data unavailable: ${e.message}`); 
      setWeather(null); 
    }
    setLoading(false);
  }, [units, user, parish]);

  const detectAndStoreAlerts = (weatherData, currentParish) => {
    const alerts = [];
    const w = weatherData.current;

    // Critical alerts
    if (w.wind?.speed > 45) {
      alerts.push({
        severity: 'critical',
        title: 'SEVERE WIND WARNING',
        message: `Dangerous winds of ${w.wind.speed} km/h detected in ${currentParish.name}`,
        action: 'Secure loose objects. Stay indoors. Avoid coastal areas.',
        parish: currentParish.name,
        timestamp: new Date().toISOString()
      });
    }

    // High alerts
    if (w.wind?.speed > 25 && w.wind?.speed <= 45) {
      alerts.push({
        severity: 'high',
        title: 'Strong Wind Advisory',
        message: `Wind speeds reaching ${w.wind.speed} km/h in ${currentParish.name}`,
        action: 'Exercise caution outdoors. Secure lightweight objects.',
        parish: currentParish.name,
        timestamp: new Date().toISOString()
      });
    }

    if (w.rain > 5) {
      alerts.push({
        severity: 'high',
        title: 'Heavy Rainfall Alert',
        message: `Heavy rain (${w.rain}mm/hr) affecting ${currentParish.name}`,
        action: 'Avoid low-lying areas. Monitor for flash flooding.',
        parish: currentParish.name,
        timestamp: new Date().toISOString()
      });
    }

    // Store alerts in localStorage for admin to see
    if (alerts.length > 0) {
      const existingAlerts = JSON.parse(localStorage.getItem('detected_alerts') || '[]');
      const newAlerts = [...alerts, ...existingAlerts].slice(0, 50);
      localStorage.setItem('detected_alerts', JSON.stringify(newAlerts));
    }
  };

  const sendAlertToAllUsers = async () => {
    if (!alertMessage.trim()) {
      setSendStatus('Please enter a message');
      return;
    }

    setSending(true);
    setSendStatus('Sending alerts...');

    try {
      const response = await fetch(`${API_BASE}/send_alert.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: alertMessage,
          parish: parish.name,
          admin_email: user.email
        })
      });

      const data = await response.json();

      if (data.success) {
        setSendStatus(`✓ Alert sent to ${data.sent_count} users!`);
        setAlertMessage('');
        setTimeout(() => setSendStatus(''), 3000);
      } else {
        setSendStatus('Failed to send alerts: ' + data.error);
      }
    } catch (error) {
      setSendStatus('Error: ' + error.message);
    }

    setSending(false);
  };

  useEffect(() => { if (parish) fetchWeather(parish.lat, parish.lon, units); }, [units]);

  const selectParish = p => { setParish(p); setDropOpen(false); fetchWeather(p.lat, p.lon, units); };

  const handleLogin = async (e) => {
    e.preventDefault();
    setFormError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_BASE}/login.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');

        // Redirect admin to admin panel
        if (data.user.role === 'admin') {
          setTab('admin');
        }
      } else {
        setFormError(data.error || 'Login failed');
      }
    } catch (err) {
      setFormError('Connection error. Make sure XAMPP Apache is running.');
    } finally {
      setFormLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setFormError('');
    setFormLoading(true);

    try {
      const response = await fetch(`${API_BASE}/register.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, name, phone, parish: 'saint-george' })
      });

      const data = await response.json();

      if (data.success) {
        setUser(data.user);
        localStorage.setItem('auth_token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        setPage('dashboard');
      } else {
        setFormError(data.error || 'Registration failed');
      }
    } catch (err) {
      setFormError('Connection error.');
    } finally {
      setFormLoading(false);
    }
  };

  const logout = () => { 
    localStorage.removeItem('auth_token');
    localStorage.removeItem('user');
    setUser(null); 
    setWeather(null); 
    setParish(null); 
    setTab("dashboard");
    setPage('login');
