                          <div style={{fontSize:"13px",fontWeight:600,color:alert.severity==='critical'?T.danger:T.warning}}>{alert.title}</div>
                          <div style={{fontSize:"12px",color:T.textSub,marginTop:"4px"}}>{alert.message}</div>
                          <div style={{fontSize:"11px",color:T.muted,marginTop:"4px"}}>{new Date(alert.timestamp).toLocaleString()}</div>
                        </div>
                      ))}
                    </div>
                  );
                }
                return null;
              })()}

              {/* User Stats */}
              <div style={{...card({padding:"24px",marginBottom:"20px"})}}>
                <div style={sLabel}>System Statistics</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:"16px",marginTop:"16px"}}>
                  <div style={{padding:"20px",background:T.cardAlt,borderRadius:"10px",textAlign:"center"}}>
                    <div style={{fontSize:"32px",fontWeight:700,color:T.text}}>{users.length}</div>
                    <div style={{color:T.muted,fontSize:"12px",marginTop:"4px"}}>Total Users</div>
                  </div>
                  <div style={{padding:"20px",background:T.cardAlt,borderRadius:"10px",textAlign:"center"}}>
                    <div style={{fontSize:"32px",fontWeight:700,color:T.text}}>{users.filter(u=>u.phone).length}</div>
                    <div style={{color:T.muted,fontSize:"12px",marginTop:"4px"}}>Users with Phone</div>
                  </div>
                  <div style={{padding:"20px",background:T.cardAlt,borderRadius:"10px",textAlign:"center"}}>
                    <div style={{fontSize:"32px",fontWeight:700,color:T.success}}>Online</div>
                    <div style={{color:T.muted,fontSize:"12px",marginTop:"4px"}}>System Status</div>
                  </div>
                </div>
              </div>

              {/* Broadcast Alert */}
              <div style={{...card({padding:"24px",marginBottom:"20px"})}}>
                <div style={sLabel}>📢 Broadcast Alert to All Users</div>
                <div style={{color:T.muted,fontSize:"13px",marginBottom:"20px"}}>
                  Send weather alerts to all registered users with phone numbers
                </div>

                {sendStatus && (
                  <div style={{padding:"12px",borderRadius:"8px",background:sendStatus.includes('✓')?T.successBg:T.warningBg,border:`1px solid ${sendStatus.includes('✓')?T.success:T.warning}`,color:sendStatus.includes('✓')?T.success:T.warning,marginBottom:"16px",fontSize:"13px"}}>
                    {sendStatus}
                  </div>
                )}

                <textarea
                  value={alertMessage}
                  onChange={(e) => setAlertMessage(e.target.value)}
                  placeholder="Enter alert message (e.g., Heavy rain expected in Saint George. Avoid low-lying areas.)"
                  style={{width:"100%",minHeight:"120px",padding:"12px",borderRadius:"8px",border:`2px solid ${T.border}`,background:T.inputBg,color:T.text,fontSize:"14px",fontFamily:"'Outfit',sans-serif",marginBottom:"12px"}}
                />

                <button 
                  onClick={sendAlertToAllUsers} 
                  disabled={sending || !alertMessage.trim()}
                  style={{width:"100%",padding:"14px",borderRadius:"9px",border:"none",background:alertMessage.trim()&&!sending?T.accent:T.cardAlt,color:alertMessage.trim()&&!sending?"#fff":T.muted,fontSize:"14px",fontWeight:600,cursor:alertMessage.trim()&&!sending?"pointer":"not-allowed",fontFamily:"'Outfit',sans-serif"}}>
                  {sending ? "Sending..." : `📢 Send Alert to ${users.filter(u=>u.phone).length} Users`}
                </button>
              </div>

              {/* User List */}
              <div style={{...card({padding:"24px"})}}>
                <div style={sLabel}>Registered Users ({users.length})</div>
                <div style={{marginTop:"16px"}}>
                  {users.length === 0 ? (
                    <div style={{textAlign:"center",padding:"40px",color:T.muted}}>No users registered yet</div>
                  ) : (
                    users.map((u, i) => (
                      <div key={i} style={{padding:"12px",marginBottom:"8px",background:T.cardAlt,borderRadius:"8px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                        <div>
                          <strong style={{color:T.text}}>{u.name}</strong>
                          <div style={{fontSize:"12px",color:T.muted,marginTop:"2px"}}>{u.email}</div>
                          {u.phone && <div style={{fontSize:"11px",color:T.muted}}>📱 {u.phone}</div>}
                        </div>
                        <span style={{padding:"4px 12px",background:u.phone?T.successBg:T.dangerBg,color:u.phone?T.success:T.danger,borderRadius:"6px",fontSize:"11px",fontWeight:600}}>
                          {u.phone ? 'SMS Enabled' : 'No Phone'}
                        </span>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>
          )}

        </div>
      </div>
    </>
  );
}

export default App;
